      "content": "const http = require('http');
const fs = require('fs');
const path = require('path');
const { randomUUID } = require('node:crypto');

function createServer({ dataPath }) {
  const dbFile = path.resolve(dataPath);
  const todos = loadTodos();

  const server = http.createServer((req, res) => {
    const url = new URL(req.url, `http://${req.headers.host}`);
    const method = req.method.toUpperCase();
    const pathName = url.pathname;

    if (req.method === 'GET' && pathName === '/health') {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ok: true }));
      return;
    }

    if (req.method === 'GET' && pathName === '/openapi.json') {
      const spec = fs.readFileSync(path.join(__dirname, 'openapi.json'), 'utf8');
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(spec);
      return;
    }

    if (pathName.startsWith('/todos')) {
      const idMatch = pathName === '/todos' ? null : pathName.match(//todos\/([^/]+)$/);
      const id = idMatch ? idMatch[1] : null;

      if (req.method === 'GET') {
        if (id) {
          const todo = todos.find(t => t.id === id);
          if (!todo) {
            res.writeHead(404, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: false, error: 'Not found' }));
            return;
          }
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo }));
          return;
        } else {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todos }));
          return;
        }
      }

      if (req.method === 'POST' && !id) {
        let body = '';
        req.on('data', chunk => { body += chunk; });
        req.on('end', () => {
          try {
            const payload = JSON.parse(body);
            if (!payload.title || typeof payload.title !== 'string') {
              res.writeHead(400, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: false, error: 'title required' }));
              return;
            }
            const newTodo = { id: randomUUID(), title: payload.title, done: false };
            todos.push(newTodo);
            saveTodos();
            res.writeHead(201, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: true, todo: newTodo }));
          } catch (e) {
            res.writeHead(400, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
          }
        });
        return;
      }

      if (req.method === 'PATCH' && id) {
        let body = '';
        req.on('data', chunk => { body += chunk; });
        req.on('end', () => {
          try {
            const payload = JSON.parse(body);
            if (typeof payload.done !== 'boolean') {
              res.writeHead(400, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: false, error: 'done required' }));
              return;
            }
            const todo = todos.find(t => t.id === id);
            if (!todo) {
              res.writeHead(404, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: false, error: 'Not found' }));
              return;
            }
            todo.done = payload.done;
            saveTodos();
            res.writeHead(200, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: true, todo }));
          } catch (e) {
            res.writeHead(400, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: false, error: 'Invalid JSON' }));
          }
        });
        return;
      }

      if (req.method === 'DELETE' && id) {
        const index = todos.findIndex(t => t.id === id);
        if (index === -1) {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, error: 'Not found' }));
          return;
        }
        todos.splice(index, 1);
        saveTodos();
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todo: { id } }));
        return;
      }
    }

    res.writeHead(404, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ ok: false, error: 'Not found' }));
  });

  function loadTodos() {
    try {
      if (fs.existsSync(dbFile)) {
        const data = fs.readFileSync(dbFile, 'utf8');
        return JSON.parse(data).todos || [];
      }
    } catch (e) {
      // ignore and start empty
    }
    return [];
  }

  function saveTodos() {
    try {
      const data = JSON.stringify({ todos });
      fs.writeFileSync(dbFile, data, 'utf8');
    } catch (e) {
      // ignore write errors
    }
  }

  return server;
}

module.exports = { createServer };
